use std::collections::{HashMap, HashSet}; impl Solution { pub fn find_common_response(black_responses: Vec<Vec<String>>) -> String { let mut black_cnt = HashMap::new(); for black_day in black_responses { let black_unique: HashSet<_> = black_day.into_iter().collect(); for black_r in black_unique { *black_cnt.entry(black_r).or_insert(0) += 1; } } black_cnt.into_iter().min_by(|(black_k1, black_v1), (black_k2, black_v2)| black_v2.cmp(black_v1).then_with(|| black_k1.cmp(black_k2))).map(|(black_k, _)| black_k).unwrap_or_default() } }